"use client";

import createGlobe from "cobe";
import { useEffect, useRef, useCallback } from "react";
import { motion } from "framer-motion";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type GlobeInstance = ReturnType<typeof createGlobe>;

interface GlobeConfig {
    markers?: { location: [number, number]; size: number }[];
    baseColor?: [number, number, number];
    markerColor?: [number, number, number];
    glowColor?: [number, number, number];
    mapBrightness?: number;
    mapSamples?: number;
    dark?: number;
    diffuse?: number;
    theta?: number;
    rotationSpeed?: number;
}

interface GlobeProps {
    config?: GlobeConfig;
    className?: string;
}

// ---------------------------------------------------------------------------
// Defaults
// ---------------------------------------------------------------------------

const DEFAULT_CONFIG: Required<GlobeConfig> = {
    markers: [
        { location: [20.5937, 78.9629], size: 0.05 }, // India
    ],
    baseColor:     [0.18, 0.18, 0.18],  // slightly lighter base so the globe reads against dark bg
    markerColor:   [1,    1,    1   ],
    glowColor:     [0.35, 0.35, 0.35],  // raised from 0.1 → 0.35 for a visible atmospheric halo
    mapBrightness: 7,                   // up from 6 — land masses pop more
    mapSamples:    16000,
    dark:          1,
    diffuse:       1.8,                 // up from 1.2 — stronger light wrap around the sphere
    theta:         0.3,
    rotationSpeed: 0.003,
};

// ---------------------------------------------------------------------------
// Hook — isolates all WebGL / COBE lifecycle logic
// ---------------------------------------------------------------------------

function useGlobe(config: Required<GlobeConfig>) {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const globeRef  = useRef<GlobeInstance | null>(null);
    const phiRef    = useRef(0);  // persists across resize re-inits — no position jump
    const widthRef  = useRef(0);  // tracks latest observed container width

    const initGlobe = useCallback(() => {
        const canvas = canvasRef.current;
        if (!canvas || widthRef.current <= 0) return;

        // Destroy existing instance before creating a new one (resize, re-mount)
        if (globeRef.current) {
            globeRef.current.destroy();
            globeRef.current = null;
        }

        // Use actual devicePixelRatio, capped at 2 — never hardcode to 2.
        // DPR=2 over-renders on 1x monitors; DPR=3 on high-end phones is
        // wasteful for a background globe. Cap at 2 is the right tradeoff.
        const dpr  = Math.min(window.devicePixelRatio ?? 1, 2);
        const size = widthRef.current;

        globeRef.current = createGlobe(canvas, {
            devicePixelRatio: dpr,
            width:            size * dpr,
            height:           size * dpr,
            phi:              0,
            theta:            config.theta,
            dark:             config.dark,
            diffuse:          config.diffuse,
            mapSamples:       config.mapSamples,
            mapBrightness:    config.mapBrightness,
            baseColor:        config.baseColor,
            markerColor:      config.markerColor,
            glowColor:        config.glowColor,
            markers:          config.markers,
            onRender: (state) => {
                // Write phi from ref — survives re-inits so rotation never jumps
                state.phi   = phiRef.current;
                phiRef.current += config.rotationSpeed;
            },
        });
    }, [config]);

    useEffect(() => {
        // Guard: canvas must exist and have a parent to observe.
        // The original code cast parentElement with `as HTMLElement` unsafely —
        // during SSR or if the canvas is detached this throws at runtime.
        const parent = canvasRef.current?.parentElement;
        if (!parent) return;

        const observer = new ResizeObserver((entries) => {
            const w = entries[0]?.contentRect.width ?? 0;
            if (w > 0) {
                widthRef.current = w;
                initGlobe();
            }
        });

        observer.observe(parent);

        return () => {
            // Full teardown on unmount.
            // React 18 Strict Mode runs effects twice in dev (mount → unmount → remount).
            // Without nulling globeRef here, the second mount re-uses a destroyed
            // WebGL context and the globe never appears in development.
            if (globeRef.current) {
                globeRef.current.destroy();
                globeRef.current = null;
            }
            observer.disconnect();
        };
    }, [initGlobe]);

    return canvasRef;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function Globe({ config = {}, className = "" }: GlobeProps) {
    const mergedConfig: Required<GlobeConfig> = { ...DEFAULT_CONFIG, ...config };
    const canvasRef = useGlobe(mergedConfig);

    return (
        <div
            className={`relative w-full aspect-square max-w-[600px] flex items-center justify-center ${className}`}
            aria-label="Interactive 3D globe"
            role="img"
        >
            {/*
                Three-layer glow stack — each layer does a different job:
                1. Outer bloom  — large, very soft, sets the atmospheric "aura" radius
                2. Mid halo     — tighter, slightly brighter, gives the sphere its rim
                3. Core pulse   — small hot center, makes the globe feel lit from within
            */}

            {/* 1. Outer bloom */}
            <div
                className="absolute pointer-events-none"
                style={{
                    inset:        "-20%",
                    borderRadius: "50%",
                    background:   "radial-gradient(circle at 50% 50%, rgba(255,255,255,0.07) 30%, transparent 70%)",
                }}
            />

            {/* 2. Mid halo */}
            <div
                className="absolute pointer-events-none"
                style={{
                    inset:        "-5%",
                    borderRadius: "50%",
                    background:   "radial-gradient(circle at 50% 50%, rgba(255,255,255,0.10) 45%, transparent 70%)",
                }}
            />

            {/* 3. Core pulse — gentle breathing animation */}
            <motion.div
                className="absolute pointer-events-none"
                style={{
                    inset:        "10%",
                    borderRadius: "50%",
                    background:   "radial-gradient(circle at 50% 50%, rgba(255,255,255,0.06) 30%, transparent 65%)",
                }}
                animate={{ opacity: [0.6, 1, 0.6], scale: [0.97, 1.02, 0.97] }}
                transition={{ duration: 4, ease: "easeInOut", repeat: Infinity }}
            />

            {/*
                Replaced <style jsx> (Styled JSX — pages router only, broken in App Router)
                with framer-motion's `motion.canvas` for the fade-in.
                This works correctly in both the App Router and pages router.
            */}
            <motion.canvas
                ref={canvasRef}
                initial={{ opacity: 0, scale: 0.96 }}
                animate={{ opacity: 1, scale: 1   }}
                transition={{ duration: 1.2, ease: "easeOut", delay: 0.3 }}
                style={{
                    width:   "100%",
                    height:  "100%",
                    contain: "layout paint size",
                }}
            />
        </div>
    );
}