import React from 'react';
import { motion } from 'framer-motion';
import {
    SiReact, SiNextdotjs, SiTypescript, SiTailwindcss, SiFramer, SiSanity,
    SiContentful, SiNodedotjs, SiExpress, SiPostgresql, SiMongodb, SiPrisma,
    SiZod, SiPnpm, SiBun, SiGit, SiGithub, SiVercel,
    SiAmazonwebservices, SiDocker, SiExpo, SiClerk, SiLinux
} from "react-icons/si";
import { HiOutlineCube } from "react-icons/hi";

export function Skillset() {
    const skills = [
        { name: "ReactJS", icon: SiReact, color: "#61DAFB" },
        { name: "NextJS", icon: SiNextdotjs, color: "#ffffff" },
        { name: "TypeScript", icon: SiTypescript, color: "#3178C6" },
        { name: "Tailwind CSS", icon: SiTailwindcss, color: "#06B6D4" },
        { name: "Motion", icon: SiFramer, color: "#0055FF" },
        { name: "Sanity", icon: SiSanity, color: "#F03E2F" },
        { name: "Contentful", icon: SiContentful, color: "#2478CC" },
        { name: "NodeJS", icon: SiNodedotjs, color: "#339933" },
        { name: "ExpressJS", icon: SiExpress, color: "#ffffff" },
        { name: "PostgreSQL", icon: SiPostgresql, color: "#4169E1" },
        { name: "MongoDB", icon: SiMongodb, color: "#47A248" },
        { name: "Prisma", icon: SiPrisma, color: "#2D3748" },
        { name: "Zustand", icon: HiOutlineCube, color: "#764ABC" },
        { name: "Zod", icon: SiZod, color: "#3E67B1" },
        { name: "pnpm", icon: SiPnpm, color: "#F69220" },
        { name: "Bun", icon: SiBun, color: "#FBF0DF" },
        { name: "Git", icon: SiGit, color: "#F05032" },
        { name: "GitHub", icon: SiGithub, color: "#ffffff" },
        { name: "Vercel", icon: SiVercel, color: "#ffffff" },
        { name: "AWS", icon: SiAmazonwebservices, color: "#FF9900" },
        { name: "Docker", icon: SiDocker, color: "#2496ED" },
        { name: "Expo", icon: SiExpo, color: "#ffffff" },
        { name: "Clerk", icon: SiClerk, color: "#6C47FF" },
        { name: "Linux", icon: SiLinux, color: "#FCC624" }
    ];

    return (
        <section className="relative z-10 min-h-screen bg-white dark:bg-[#050505] text-black dark:text-white py-32 flex flex-col items-center justify-center overflow-hidden">

            {/* Background 3D Graphic Placeholder */}
            {/* The user provided a 3D glass flower graphic. We will use a soft glowing radial gradient and a blurred shape placeholder for now to mimic the aesthetics of the dark background and focus the attention on the grid */}
            <div className="absolute top-1/4 left-1/2 -translate-x-1/2 w-[60vw] h-[60vw] max-w-[800px] max-h-[800px] bg-black/5 dark:bg-white/5 rounded-full blur-[100px] pointer-events-none" />

            <div className="relative z-10 flex flex-col items-center text-center px-4 mb-20">
                <p className="text-xs font-bold tracking-[0.2em] text-neutral-400 uppercase mb-4">
                    My Skillset
                </p>
                <h2 className="text-5xl md:text-6xl lg:text-7xl font-black tracking-tight leading-tight">
                    The Magic <span className="bg-gradient-to-r from-blue-500 via-indigo-500 to-pink-500 bg-clip-text text-transparent font-serif italic pr-4 pb-2">Behind</span>
                </h2>
            </div>

            {/* Interactive Grid */}
            <div className="relative z-10 flex flex-wrap justify-center gap-4 max-w-5xl mx-auto px-4">
                {skills.map((skill, index) => (
                    <motion.div
                        key={skill.name}
                        initial={{ opacity: 0, y: 20 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ duration: 0.5, delay: index * 0.03 }}
                        whileHover={{ scale: 1.05 }}
                        className="flex items-center gap-3 px-6 py-3 rounded-full bg-neutral-50 dark:bg-[#111] border border-neutral-200 dark:border-neutral-800 hover:bg-neutral-100 dark:hover:bg-neutral-800 hover:border-neutral-300 dark:hover:border-neutral-700 transition-colors shadow-sm dark:shadow-none cursor-pointer group"
                    >
                        {skill.icon && (
                            <skill.icon
                                className="w-5 h-5 opacity-70 group-hover:opacity-100 transition-opacity duration-300"
                                style={{ color: skill.color }}
                            />
                        )}
                        <span className="text-sm font-medium text-neutral-600 dark:text-neutral-300 group-hover:text-black dark:group-hover:text-white transition-colors">
                            {skill.name}
                        </span>
                    </motion.div>
                ))}
            </div>

        </section>
    );
}
